import { useGetOneQueryOptions } from "../../../query-helpers/useGetOneQueryOptions";
import type { PublicV3ActionPageResponse } from "../../../types/actionPage";
import { actionPageQueryKeys } from "./queryKeys";

type Params = {
  actionPageSlug: string;
  accountSlug: string;
};

export const useGetPublicActionPageQueryOptions = ({
  actionPageSlug,
  accountSlug,
  ...options
}: Params) => {
  return useGetOneQueryOptions<PublicV3ActionPageResponse>(
    `/action_pages/${actionPageSlug}`,
    { account_slug: accountSlug },
    actionPageQueryKeys.entity({
      namespace: "public",
      parameters: { actionPageSlug },
    }).queryKey,
    {
      namespace: "public",
      staleTime: 60000,
      ...options,
    },
  );
};

